{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "引言：AI的起源与定义",
      "pages": [
        {
          "title": "什么是人工智能？",
          "bullets": [
            "人工智能（AI）是研究、开发用于模拟、延伸和扩展人的智能的理论、方法、技术及应用系统的一门技术科学。",
            "核心目标：使机器能够胜任一些通常需要人类智能才能完成的复杂工作。",
            "发展历程：经历了多次繁荣与低谷，至今已成为推动社会变革的核心技术。"
          ],
          "notes": "开场提问：你心目中的AI是什么？从电影中的机器人讲起，引出科学定义。"
        },
        {
          "title": "课程目标与内容概览",
          "bullets": [
            "目标：系统梳理AI发展脉络，理解技术演进背后的逻辑与驱动力。",
            "内容：从萌芽期到当前大模型时代，涵盖关键人物、事件与突破。",
            "结构：按时间分章节，每章聚焦一个核心范式或时代特征。",
            "受众：软件工程课程师生，侧重技术演变与工程实践启示。"
          ],
          "notes": "说明本PPT将如何组织，以及学习后能获得什么。为后续章节做铺垫。"
        }
      ]
    },
    {
      "title": "第一幕：梦想的诞生与第一次寒冬（1950s-1970s）",
      "pages": [
        {
          "title": "萌芽期：理论奠基与学科诞生",
          "bullets": [
            "1950年：艾伦·图灵发表《计算机器与智能》，提出“图灵测试”。",
            "1956年：达特茅斯会议，约翰·麦卡锡等人正式提出“人工智能”术语。",
            "早期成果：逻辑理论家程序、通用问题求解器、感知机模型。",
            "时代局限：计算能力不足，算法简单，只能解决“玩具问题”。"
          ],
          "notes": "重点讲述图灵测试的思想实验意义，以及达特茅斯会议的历史地位。"
        },
        {
          "title": "第一次繁荣与寒冬",
          "bullets": [
            "1970s初：专家系统雏形出现（如MYCIN医疗诊断、DENDRAL化学分析）。",
            "技术特点：基于逻辑推理和符号计算，在狭窄领域内有效。",
            "1973年：莱特希尔报告严厉批评AI进展，指出“通用智能”承诺落空。",
            "后果：政府资金大幅削减，AI研究进入第一次“寒冬”。"
          ],
          "notes": "对比早期乐观预期与现实落差，解释寒冬的成因不仅是技术，还有期望管理。"
        }
      ]
    },
    {
      "title": "第二幕：知识工程与机器学习的交替（1980s-1990s）",
      "pages": [
        {
          "title": "专家系统时代：知识就是力量",
          "bullets": [
            "1980s：AI以“专家系统”形式复兴，核心是编码人类专家的规则。",
            "商业成功案例：XCON系统为DEC公司每年节省数千万美元。",
            "国家项目推动：日本“第五代计算机”计划，美国MCC项目。",
            "瓶颈：系统脆弱、维护成本高、知识获取困难（知识工程瓶颈）。"
          ],
          "notes": "举例说明专家系统的工作原理，并分析其兴衰对软件工程（知识表示）的启示。"
        },
        {
          "title": "转向数据驱动：统计机器学习崛起",
          "bullets": [
            "1990s：研究范式从“基于规则”的符号主义转向“基于数据”的连接主义/统计学习。",
            "算法里程碑：支持向量机（SVM，1995）、随机森林（1997）。",
            "标志性事件：1997年IBM“深蓝”击败国际象棋世界冠军卡斯帕罗夫。",
            "意义：证明了在规则明确的复杂博弈中，算力与搜索算法可以超越人类。"
          ],
          "notes": "强调范式转变的重要性：从“教计算机思考”到“让计算机从数据中学习”。"
        }
      ]
    },
    {
      "title": "第三幕：深度学习的革命与大模型时代（2010s-至今）",
      "pages": [
        {
          "title": "深度学习爆发：三驾马车驱动",
          "bullets": [
            "三大驱动力：大数据（互联网）、强算力（GPU）、新算法（深度神经网络）。",
            "关键里程碑：2012年AlexNet在ImageNet竞赛中碾压性获胜。",
            "颠覆性成就：2016年AlphaGo击败围棋冠军李世石，攻克“人类智慧高地”。",
            "技术浪潮：卷积神经网络（CNN）、循环神经网络（RNN）广泛应用于视觉、语音。"
          ],
          "notes": "用AlexNet的错误率对比图直观展示性能飞跃。解释深度学习为何在此时成功。"
        },
        {
          "title": "NLP革命：从Transformer到大模型",
          "bullets": [
            "2017年：Transformer架构诞生，成为现代NLP的基石。",
            "预训练范式：BERT（2018，双向理解）、GPT系列（生成式预训练）。",
            "涌现能力：模型规模超过某个阈值后，出现意想不到的新能力。",
            "多模态演进：模型从理解文本，到处理图像、音频、视频。"
          ],
          "notes": "简要图解Transformer的自注意力机制。说明“预训练+微调”范式如何改变AI开发。"
        },
        {
          "title": "生成式AI与ChatGPT现象",
          "bullets": [
            "2022年11月：ChatGPT发布，以对话形式引爆公众AI热潮。",
            "增长奇迹：5天用户破百万，2个月月活破亿，史上最快。",
            "技术内核：基于GPT系列大语言模型，采用人类反馈强化学习（RLHF）对齐。",
            "产业跟进：全球科技巨头与创业公司纷纷推出同类大模型产品。"
          ],
          "notes": "展示ChatGPT的增长曲线图。讨论其成功不仅是技术，更是产品化和交互方式的胜利。"
        },
        {
          "title": "全球竞争与中国力量",
          "bullets": [
            "国际格局：OpenAI（GPT）、Google（Gemini）、Anthropic（Claude）领先。",
            "中国主要玩家：百度（文心一言）、阿里（通义千问）、智谱AI（ChatGLM）、深度求索（DeepSeek）。",
            "技术路线：闭源与开源并存，开源模型（如Llama）性能快速追赶。",
            "当前趋势：模型性能趋同，竞争焦点转向成本、应用生态与多模态能力。"
          ],
          "notes": "客观介绍中美AI发展特点，可简要对比不同模型在评测中的表现。"
        }
      ]
    },
    {
      "title": "第四幕：反思、挑战与未来",
      "pages": [
        {
          "title": "当前面临的严峻挑战",
          "bullets": [
            "技术缺陷：“幻觉”问题（生成虚假信息）、可解释性差（黑箱模型）。",
            "资源与伦理：巨额算力消耗与碳排放、训练数据版权争议。",
            "安全与对齐：如何确保AI的目标与行为符合人类价值观（对齐问题）。",
            "社会影响：就业冲击、信息真伪、偏见放大与AGI的长期风险。"
          ],
          "notes": "结合具体案例（如法律引用虚假案例）说明挑战的紧迫性。引发学生思考。"
        },
        {
          "title": "未来技术演进方向",
          "bullets": [
            "高效化：模型小型化、推理优化，以适应边缘设备部署。",
            "智能化升级：从感知智能到决策智能、具身智能（机器人）。",
            "形态演进：AI Agent（能自主规划、执行复杂任务的智能体）。",
            "终极探索：迈向更通用、更可靠、更可控的通用人工智能（AGI）。"
          ],
          "notes": "描绘未来应用场景，如AI科学家、个人数字助理、自动驾驶城市等。"
        },
        {
          "title": "对软件工程师的启示",
          "bullets": [
            "技能更新：理解AI原理，掌握Prompt工程、模型微调与应用集成。",
            "开发范式转变：从“编写所有逻辑”到“编排与引导大模型”。",
            "责任与伦理：在开发中必须考虑公平性、透明度、隐私与安全。",
            "拥抱变化：AI是强大的工具和合作伙伴，将重塑软件开发的方方面面。"
          ],
          "notes": "回归课程受众，给出切实的学习和发展建议。鼓励积极拥抱技术变革。"
        }
      ]
    },
    {
      "title": "总结",
      "pages": [
        {
          "title": "回顾与展望",
          "bullets": [
            "发展脉络：从符号推理，到专家系统，到统计学习，再到深度学习与大模型。",
            "核心规律：突破源于算法、算力、数据三大要素的协同演进。",
            "现状：我们正处于由生成式AI驱动的、前所未有的应用爆发期。",
            "未来：挑战与机遇并存，AI的最终形态将由今天的我们共同塑造。"
          ],
          "notes": "用时间轴图示快速回顾整个发展史。结束语：AI的故事，也是人类追求智慧的故事。"
        }
      ]
    }
  ]
}
